import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import { PlusCircle, Store, ArrowLeft, MapPin, Loader2, Navigation } from 'lucide-react';
import { useAuth } from '../context/AuthContext';

// Icono de Leaflet
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
});

const DashboardVendedor = () => {
  const { user } = useAuth();
  const [locales, setLocales] = useState([]);
  const [localActivo, setLocalActivo] = useState(null);
  const [mostrarFormLocal, setMostrarFormLocal] = useState(false);
  const [buscandoDireccion, setBuscandoDireccion] = useState(false);

  const [nuevoLocal, setNuevoLocal] = useState({
    nombre: '',
    direccion: '',
    lng: -65.2176,
    lat: -26.8161
  });

  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  useEffect(() => { if (user) fetchLocales(); }, [user]);

  const fetchLocales = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/locales/vendedor/${user.id || user._id}`);
      setLocales(res.data);
    } catch (err) { console.error(err); }
  };

  // --- FUNCIÓN MÁGICA: DE COORDENADAS A CALLE ---
  const fetchAddress = async (lat, lng) => {
    setBuscandoDireccion(true);
    try {
      const response = await fetch(
        `https://nominatim.openstreetmap.org/reverse?format=jsonv2&lat=${lat}&lon=${lng}`
      );
      const data = await response.json();
      if (data.display_name) {
        // Formateamos la dirección para que no sea tan larga (Calle y Altura)
        const street = data.address.road || '';
        const houseNumber = data.address.house_number || '';
        const city = data.address.city || data.address.town || '';
        const fullDir = `${street} ${houseNumber}${street ? ',' : ''} ${city}`.trim();
        
        setNuevoLocal(prev => ({ ...prev, direccion: fullDir, lat, lng }));
      }
    } catch (error) {
      console.error("Error al obtener dirección", error);
    } finally {
      setBuscandoDireccion(false);
    }
  };

  const LocationMarker = () => {
    useMapEvents({
      click(e) {
        fetchAddress(e.latlng.lat, e.latlng.lng);
      },
    });
    return <Marker position={[nuevoLocal.lat, nuevoLocal.lng]} />;
  };

  const handleCrearLocal = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`${API_URL}/api/locales`, {
        ...nuevoLocal,
        vendedorId: user.id || user._id
      });
      fetchLocales();
      setMostrarFormLocal(false);
    } catch (err) { alert("Error al guardar local"); }
  };

  if (!localActivo) {
    return (
      <div style={containerStyle}>
        <div style={headerStyle}>
          <h2>Mis Locales</h2>
          <button onClick={() => setMostrarFormLocal(!mostrarFormLocal)} style={btnPrimary}>
            {mostrarFormLocal ? 'Cancelar' : <><PlusCircle size={18}/> Nuevo Local</>}
          </button>
        </div>

        {mostrarFormLocal ? (
          <div style={formCard}>
            <div style={formLayout}>
              <form onSubmit={handleCrearLocal} style={inputsContainer}>
                <h3 style={{margin:0}}>Datos del Comercio</h3>
                
                <label style={labelL}>Nombre del Local</label>
                <input style={inputS} placeholder="Ej: Miniservice El Sol" value={nuevoLocal.nombre} onChange={e => setNuevoLocal({...nuevoLocal, nombre: e.target.value})} required />
                
                <label style={labelL}>Dirección (Se actualiza al tocar el mapa)</label>
                <div style={{ position: 'relative' }}>
                  <input 
                    style={{...inputS, paddingRight: '40px'}} 
                    placeholder="Calle, Altura, Ciudad" 
                    value={nuevoLocal.direccion} 
                    onChange={e => setNuevoLocal({...nuevoLocal, direccion: e.target.value})} 
                    required 
                  />
                  {buscandoDireccion && <Loader2 size={18} style={spinner} />}
                </div>

                <div style={coordsBadge}>
                  <Navigation size={14} /> {nuevoLocal.lat.toFixed(5)} , {nuevoLocal.lng.toFixed(5)}
                </div>

                <button type="submit" style={btnSubmit} disabled={buscandoDireccion}>
                  Confirmar y Crear Local
                </button>
              </form>

              <div style={mapWrapper}>
                <p style={mapHint}>Toca el mapa donde se encuentra tu local:</p>
                <MapContainer center={[nuevoLocal.lat, nuevoLocal.lng]} zoom={14} style={mapStyle}>
                  <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
                  <LocationMarker />
                </MapContainer>
              </div>
            </div>
          </div>
        ) : (
          <div style={gridLocales}>
            {locales.map(l => (
              <div key={l._id} style={cardLocal} onClick={() => setLocalActivo(l)}>
                <Store size={35} color="#e67e22" />
                <h3 style={{margin:'10px 0 5px 0', fontSize: '1.1rem'}}>{l.nombre}</h3>
                <p style={{fontSize:'0.8rem', color:'#64748b', lineHeight: '1.4'}}>{l.direccion}</p>
              </div>
            ))}
          </div>
        )}
      </div>
    );
  }

  return (
    <div style={containerStyle}>
       <button onClick={() => setLocalActivo(null)} style={btnBack}><ArrowLeft size={18}/> Volver al listado</button>
       <h1 style={{marginTop: '15px'}}>{localActivo.nombre}</h1>
       {/* Aquí continuarías con la gestión de ofertas */}
    </div>
  );
};

// --- ESTILOS MEJORADOS ---
const containerStyle = { padding: '40px 20px', maxWidth: '1100px', margin: '0 auto', fontFamily: "'Plus Jakarta Sans', sans-serif" };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const formCard = { background: 'white', padding: '30px', borderRadius: '28px', boxShadow: '0 20px 40px rgba(0,0,0,0.06)', border: '1px solid #f1f5f9' };
const formLayout = { display: 'grid', gridTemplateColumns: '1fr 1.2fr', gap: '40px' };
const inputsContainer = { display: 'flex', flexDirection: 'column', gap: '18px' };
const labelL = { fontSize: '0.75rem', fontWeight: 'bold', color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.5px' };
const inputS = { width: '100%', padding: '14px', borderRadius: '14px', border: '2px solid #f1f5f9', fontSize: '1rem', outline: 'none', transition: 'all 0.2s', focus: { borderColor: '#e67e22' } };
const mapWrapper = { display: 'flex', flexDirection: 'column', gap: '12px' };
const mapStyle = { height: '400px', borderRadius: '20px', border: '4px solid #f8fafc' };
